window.bookSummaryJSON = "<p><i>New York Times</i> best-selling author Laurie R. King enjoys immense popularity and a resounding chorus of critical acclaim for her exquisite mysteries. <i>The God of the Hive</i> continues the thread King began in <i>The Language of Bees</i>, in which Mary Russell and her famous husband, Sherlock Holmes, face trouble with Scotland Yard and the deadliest of adversaries.</p>"; 
